-- Conferencia da quantidade de registros por tabela
SELECT 'Modalidade' AS tabela, COUNT(*) AS quantidade FROM Modalidade
UNION ALL SELECT 'Categoria', COUNT(*) FROM Categoria
UNION ALL SELECT 'Genero', COUNT(*) FROM Genero
UNION ALL SELECT 'Temporada', COUNT(*) FROM Temporada
UNION ALL SELECT 'Campeonato', COUNT(*) FROM Campeonato
UNION ALL SELECT 'Equipe', COUNT(*) FROM Equipe
UNION ALL SELECT 'Estadio', COUNT(*) FROM Estadio
UNION ALL SELECT 'Equipe_Campeonato', COUNT(*) FROM Equipe_Campeonato
UNION ALL SELECT 'Atleta', COUNT(*) FROM Atleta
UNION ALL SELECT 'Atleta_Equipe', COUNT(*) FROM Atleta_Equipe
UNION ALL SELECT 'Partida', COUNT(*) FROM Partida
UNION ALL SELECT 'Resultado_Partida', COUNT(*) FROM Resultado_Partida
UNION ALL SELECT 'Evento_Partida', COUNT(*) FROM Evento_Partida
UNION ALL SELECT 'Pontuacoes_Atletas', COUNT(*) FROM Pontuacoes_Atletas
UNION ALL SELECT 'Arbitro', COUNT(*) FROM Arbitro
UNION ALL SELECT 'Arbitro_Partida', COUNT(*) FROM Arbitro_Partida;
